import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

/**
 * Tests for annotations inside TYPE_ARGUMENT_LIST
 * Issue: https://github.com/pinterest/ktlint/issues/673
 */
class AnnotationRuleTypeArgumentTest {
    private val annotationRuleAssertThat = assertThatRule { AnnotationRule() }

    @Test
    fun `Issue 673 - Given a type with multiple annotations inside a TypeArgumentList`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<@Valid @NotNull FooDto>,
            )
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 673 - Given a type with multiple annotations with parameters inside a TypeArgumentList`() {
        val code =
            """
            data class FooRequestDto(
                val data: List<@Ann("foo") @Valid @NotNull FooDto>,
            )
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 673 - Given multiple types with multiple annotations inside a TypeArgumentList`() {
        val code =
            """
            val moreComplexMap: Map<@Foo @Bar SimpleDto, @Foo @Bar LongerButReasonableDto>
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 673 - Given a type with multiple annotations inside a generic with many type arguments`() {
        val code =
            """
            val property: SomeCustomTypeWithGenerics<@Foo @Bar SimpleDto, @Foo @Bar LongerDto, @Foo @Bar ExtremeLongDto>
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 673 - Given a type with annotation containing complex parameters inside a TypeArgumentList`() {
        val code =
            """
            val property: List<@ComplexAnnotationWithParameters("foo bar") @Foo SimpleDto>
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Issue 673 - Given a function with type argument containing multiple annotations`() {
        val code =
            """
            fun doSomething() {
                funWithGenericsCall<@JvmSuppressWildcards(true) @Foo Int>()
            }
            """.trimIndent()
        annotationRuleAssertThat(code).hasNoLintViolations()
    }

